// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Get recent activity feed across all joined forums
	// (GET /api/activity)
	GetActivity(ctx context.Context, request GetActivityRequestObject) (GetActivityResponseObject, error)
	// Log out
	// (POST /api/auth/logout)
	Logout(ctx context.Context, request LogoutRequestObject) (LogoutResponseObject, error)
	// Get current auth session
	// (GET /api/auth/session)
	GetSession(ctx context.Context, request GetSessionRequestObject) (GetSessionResponseObject, error)
	// Initiate a call in a conversation
	// (POST /api/calls)
	InitiateCall(ctx context.Context, request InitiateCallRequestObject) (InitiateCallResponseObject, error)
	// End an active call
	// (POST /api/calls/{callId}/end)
	EndCall(ctx context.Context, request EndCallRequestObject) (EndCallResponseObject, error)
	// Accept or decline a call
	// (POST /api/calls/{callId}/respond)
	RespondToCall(ctx context.Context, request RespondToCallRequestObject) (RespondToCallResponseObject, error)
	// Get a LiveKit access token for a call
	// (POST /api/calls/{callId}/token)
	GetCallToken(ctx context.Context, request GetCallTokenRequestObject) (GetCallTokenResponseObject, error)
	// List all conversations for the current user
	// (GET /api/conversations)
	ListConversations(ctx context.Context, request ListConversationsRequestObject) (ListConversationsResponseObject, error)
	// Create a group conversation
	// (POST /api/conversations)
	CreateGroupConversation(ctx context.Context, request CreateGroupConversationRequestObject) (CreateGroupConversationResponseObject, error)
	// Get or create a 1:1 DM conversation
	// (POST /api/conversations/dm)
	GetOrCreateDM(ctx context.Context, request GetOrCreateDMRequestObject) (GetOrCreateDMResponseObject, error)
	// Get a conversation by ID
	// (GET /api/conversations/{conversationId})
	GetConversation(ctx context.Context, request GetConversationRequestObject) (GetConversationResponseObject, error)
	// Update a conversation (rename, add/remove members)
	// (PATCH /api/conversations/{conversationId})
	UpdateConversation(ctx context.Context, request UpdateConversationRequestObject) (UpdateConversationResponseObject, error)
	// Leave a conversation
	// (DELETE /api/conversations/{conversationId}/members/me)
	LeaveConversation(ctx context.Context, request LeaveConversationRequestObject) (LeaveConversationResponseObject, error)
	// Get messages in a conversation
	// (GET /api/conversations/{conversationId}/messages)
	GetMessages(ctx context.Context, request GetMessagesRequestObject) (GetMessagesResponseObject, error)
	// Send a message in a conversation
	// (POST /api/conversations/{conversationId}/messages)
	SendMessage(ctx context.Context, request SendMessageRequestObject) (SendMessageResponseObject, error)
	// Mark all messages in a conversation as read
	// (POST /api/conversations/{conversationId}/read)
	MarkConversationRead(ctx context.Context, request MarkConversationReadRequestObject) (MarkConversationReadResponseObject, error)
	// Server-sent event stream (DMs, notifications, calls)
	// (GET /api/events/stream)
	GetEventStream(ctx context.Context, request GetEventStreamRequestObject) (GetEventStreamResponseObject, error)
	// Delete a forum
	// (DELETE /api/forums)
	DeleteForum(ctx context.Context, request DeleteForumRequestObject) (DeleteForumResponseObject, error)
	// List/search public forums
	// (GET /api/forums)
	ListForums(ctx context.Context, request ListForumsRequestObject) (ListForumsResponseObject, error)
	// Register a new forum
	// (POST /api/forums)
	RegisterForum(ctx context.Context, request RegisterForumRequestObject) (RegisterForumResponseObject, error)
	// Get forums owned by current user
	// (GET /api/forums/owned)
	GetOwnedForums(ctx context.Context, request GetOwnedForumsRequestObject) (GetOwnedForumsResponseObject, error)
	// Get personalized forum recommendations
	// (GET /api/forums/recommended)
	GetRecommendedForums(ctx context.Context, request GetRecommendedForumsRequestObject) (GetRecommendedForumsResponseObject, error)
	// List all forum tags
	// (GET /api/forums/tags)
	ListForumTags(ctx context.Context, request ListForumTagsRequestObject) (ListForumTagsResponseObject, error)
	// Health check
	// (GET /api/health)
	GetHealth(ctx context.Context, request GetHealthRequestObject) (GetHealthResponseObject, error)
	// Delete current user's account
	// (DELETE /api/identity)
	DeleteIdentity(ctx context.Context, request DeleteIdentityRequestObject) (DeleteIdentityResponseObject, error)
	// Get current user's profile
	// (GET /api/identity)
	GetIdentity(ctx context.Context, request GetIdentityRequestObject) (GetIdentityResponseObject, error)
	// Update current user's profile
	// (PUT /api/identity)
	UpdateIdentity(ctx context.Context, request UpdateIdentityRequestObject) (UpdateIdentityResponseObject, error)
	// Leave a forum
	// (DELETE /api/memberships)
	LeaveForum(ctx context.Context, request LeaveForumRequestObject) (LeaveForumResponseObject, error)
	// List current user's forum memberships
	// (GET /api/memberships)
	GetMemberships(ctx context.Context, request GetMembershipsRequestObject) (GetMembershipsResponseObject, error)
	// Update forum auth state for a membership
	// (POST /api/memberships)
	UpdateMembershipAuth(ctx context.Context, request UpdateMembershipAuthRequestObject) (UpdateMembershipAuthResponseObject, error)
	// Toggle notification muting for a membership
	// (PUT /api/memberships)
	ToggleMembershipMute(ctx context.Context, request ToggleMembershipMuteRequestObject) (ToggleMembershipMuteResponseObject, error)
	// Join a forum by domain
	// (POST /api/memberships/join)
	JoinForum(ctx context.Context, request JoinForumRequestObject) (JoinForumResponseObject, error)
	// Get notifications for current user
	// (GET /api/notifications)
	GetNotifications(ctx context.Context, request GetNotificationsRequestObject) (GetNotificationsResponseObject, error)
	// Mark a notification as read
	// (POST /api/notifications/read)
	MarkNotificationRead(ctx context.Context, request MarkNotificationReadRequestObject) (MarkNotificationReadResponseObject, error)
	// Mark all notifications as read
	// (POST /api/notifications/read-all)
	MarkAllNotificationsRead(ctx context.Context, request MarkAllNotificationsReadRequestObject) (MarkAllNotificationsReadResponseObject, error)
	// Get unread notification count
	// (GET /api/notifications/unread)
	GetUnreadCount(ctx context.Context, request GetUnreadCountRequestObject) (GetUnreadCountResponseObject, error)
	// Send presence heartbeat
	// (POST /api/presence/heartbeat)
	PresenceHeartbeat(ctx context.Context, request PresenceHeartbeatRequestObject) (PresenceHeartbeatResponseObject, error)
	// Batch-fetch online status for a list of user IDs
	// (GET /api/presence/status)
	GetPresenceStatus(ctx context.Context, request GetPresenceStatusRequestObject) (GetPresenceStatusResponseObject, error)
	// Search user profiles by username or display name
	// (GET /api/profiles/search)
	SearchProfiles(ctx context.Context, request SearchProfilesRequestObject) (SearchProfilesResponseObject, error)
	// Subscribe or unsubscribe from push notifications
	// (POST /api/push)
	ManagePushSubscription(ctx context.Context, request ManagePushSubscriptionRequestObject) (ManagePushSubscriptionResponseObject, error)
	// Forum → Forumline single notification push
	// (POST /api/webhooks/notification)
	WebhookNotification(ctx context.Context, request WebhookNotificationRequestObject) (WebhookNotificationResponseObject, error)
	// Forum → Forumline batch notification push
	// (POST /api/webhooks/notifications)
	WebhookNotificationBatch(ctx context.Context, request WebhookNotificationBatchRequestObject) (WebhookNotificationBatchResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// GetActivity operation middleware
func (sh *strictHandler) GetActivity(w http.ResponseWriter, r *http.Request) {
	var request GetActivityRequestObject

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.GetActivity(ctx, request.(GetActivityRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "GetActivity")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(GetActivityResponseObject); ok {
		if err := validResponse.VisitGetActivityResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

